@namespace Lumeo

@*
    Hero — landing-page hero band. Part of the 3.4 Splash Kit. Provides
    a centered, max-width content rail with an optional Eyebrow chip,
    Title, Subtitle, Actions slot, and a Media slot for the side
    illustration. Layout collapses to a single column under sm:.
*@

<section class="@CssClass" aria-labelledby="@TitleId" @attributes="AdditionalAttributes">
    <div class="@($"mx-auto max-w-6xl px-6 py-16 sm:py-24 {GridClass}")">
        <div class="@($"flex flex-col {AlignClass}")">
            @if (Eyebrow is not null)
            {
                <div class="mb-4">
                    @Eyebrow
                </div>
            }
            @if (!string.IsNullOrWhiteSpace(Title))
            {
                <h1 id="@TitleId" class="text-4xl sm:text-5xl lg:text-6xl font-bold tracking-tight text-foreground">@Title</h1>
            }
            @TitleSlot
            @if (!string.IsNullOrWhiteSpace(Subtitle))
            {
                <p class="mt-4 text-lg text-muted-foreground max-w-2xl">@Subtitle</p>
            }
            @SubtitleSlot
            @if (Actions is not null)
            {
                <div class="mt-8 flex flex-wrap gap-3 @ActionsAlignClass">
                    @Actions
                </div>
            }
        </div>
        @if (Media is not null)
        {
            <div class="flex items-center justify-center">
                @Media
            </div>
        }
    </div>
</section>

@code {
    /// <summary>Plain-text headline, rendered as an <c>h1</c> that also names the section landmark.
    /// Ignored (and the <c>h1</c> omitted) when <see cref="TitleSlot"/> is used instead.</summary>
    [Parameter] public string? Title { get; set; }
    /// <summary>Rich content slot for the headline, for when a plain-text <see cref="Title"/> isn't
    /// enough (e.g. inline styling, a gradient span). Rendered alongside <see cref="Title"/> if both are set.</summary>
    [Parameter] public RenderFragment? TitleSlot { get; set; }
    /// <summary>Plain-text supporting copy below the title. Ignored when <see cref="SubtitleSlot"/> is used instead.</summary>
    [Parameter] public string? Subtitle { get; set; }
    /// <summary>Rich content slot for the supporting copy, for when plain-text <see cref="Subtitle"/> isn't enough.</summary>
    [Parameter] public RenderFragment? SubtitleSlot { get; set; }
    /// <summary>Small chip/label rendered above the title (e.g. "New" or a category tag).</summary>
    [Parameter] public RenderFragment? Eyebrow { get; set; }
    /// <summary>Call-to-action buttons/links rendered below the subtitle.</summary>
    [Parameter] public RenderFragment? Actions { get; set; }
    /// <summary>Side illustration/media slot. When set, the hero switches to a two-column grid layout
    /// with the text on one side and this media on the other.</summary>
    [Parameter] public RenderFragment? Media { get; set; }
    /// <summary>Horizontal alignment of the text column and its actions. Default: <see cref="HeroAlignment.Start"/>.</summary>
    [Parameter] public HeroAlignment Alignment { get; set; } = HeroAlignment.Start;
    /// <summary>Additional CSS classes merged onto the root <c>section</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Additional HTML attributes captured and forwarded to the root <c>section</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("w-full", Class);

    // Name the <section> landmark via its heading so AT exposes it as a region
    // with an accessible name (#297). Null when there's no Title — a TitleSlot-
    // only consumer can still supply aria-label/aria-labelledby via attributes.
    private readonly string _titleId = $"hero-title-{Guid.NewGuid():N}";
    private string? TitleId => string.IsNullOrWhiteSpace(Title) ? null : _titleId;

    private string GridClass => Media is not null
        ? "grid gap-10 lg:grid-cols-2 items-center"
        : "";

    private string AlignClass => Alignment switch
    {
        HeroAlignment.Center => "items-center text-center",
        HeroAlignment.End => "items-end text-end",
        _ => "items-start text-start"
    };

    private string ActionsAlignClass => Alignment switch
    {
        HeroAlignment.Center => "justify-center",
        HeroAlignment.End => "justify-end",
        _ => "justify-start"
    };

    public enum HeroAlignment { Start, Center, End }
}
